import React, { useState } from 'react';
import { useLocation } from 'react-router-dom';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, CardElement, useStripe, useElements } from '@stripe/react-stripe-js';
import "./payment.css"

const stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY);

const API_BASE_URL = 'https://e-nutritionist-08e05a1c6652.herokuapp.com'; 
const API_Local_Host = "http://localhost:3000"

const CheckoutForm = ({ orderId, onPaymentSuccess }) => {
  const location = useLocation();
  const { amount } = location.state || {};

  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState(null);

  const url = API_BASE_URL;

  const handleSubmit = async (event) => {
    event.preventDefault();
  
    if (!stripe || !elements) {
      return;
    }
  
    const cardElement = elements.getElement(CardElement);
  
    const { error, paymentMethod } = await stripe.createPaymentMethod({
      type: 'card',
      card: cardElement,
    });
  
    if (error) {
      setError(error.message);
      return;
    }
  
    const response = await fetch(`${url}/payments`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        stripeToken: paymentMethod.id,
        orderId: orderId,
        amount: orderTotalAmount, // Add this line
      }),
    });
  
    if (!response.ok) {
      const paymentError = await response.json();
      setError(paymentError.error);
    } else {
      const paymentResult = await response.json();
      onPaymentSuccess(paymentResult);
    }
  };
  
  

  return (
    <form className="payment-form" onSubmit={handleSubmit}>
      <h2>Complete Your Payment</h2>
      <CardElement className="StripeElement" />
      <button type="submit" disabled={!stripe}>
        Pay Now
      </button>
      {error && <div className="error-message">{error}</div>}
    </form>
  );
};


const PaymentSection = ({ orderId, onPaymentSuccess }) => (
  <Elements stripe={stripePromise}>
    <CheckoutForm orderId={orderId} amount={amount} onPaymentSuccess={onPaymentSuccess} />
  </Elements>
);

export default PaymentSection;
